 804 static std::optional<unsigned>
 805 shouldPragmaUnroll(Loop *L, const PragmaInfo &PInfo,
 806                    const unsigned TripMultiple, const unsigned TripCount,
 807                    unsigned MaxTripCount, const UnrollCostEstimator UCE,
 808                    const TargetTransformInfo::UnrollingPreferences &UP) {
