 811   // 1st priority is unroll count set by "unroll-count" option.
 812 
 813   if (PInfo.UserUnrollCount) {
 814     if (UP.AllowRemainder &&
 815         UCE.getUnrolledLoopSize(UP, (unsigned)UnrollCount) < UP.Threshold)
 816       return (unsigned)UnrollCount;
 817   }
 818 
 819   // 2nd priority is unroll count set by pragma.
 820   if (PInfo.PragmaCount > 0) {
 821     if ((UP.AllowRemainder || (TripMultiple % PInfo.PragmaCount == 0)))
 822       return PInfo.PragmaCount;
 823   }
 824 
 825   if (PInfo.PragmaFullUnroll && TripCount != 0) {
 826     // Certain cases with UBSAN can cause trip count to be calculated as
 827     // INT_MAX, Block full unrolling at a reasonable limit so that the compiler
 828     // doesn't hang trying to unroll the loop. See PR77842
 829     if (TripCount > PragmaUnrollFullMaxIterations) {
 830       LLVM_DEBUG(dbgs() << "Won't unroll; trip count is too large\n");
 831       return std::nullopt;
 832     }
 833 
 834     return TripCount;
 835   }
 836 
 837   if (PInfo.PragmaEnableUnroll && !TripCount && MaxTripCount &&
 838       MaxTripCount <= UP.MaxUpperBound)
 839     return MaxTripCount;
