 844 static std::optional<unsigned> shouldFullUnroll(
 845     Loop *L, const TargetTransformInfo &TTI, DominatorTree &DT,
 846     ScalarEvolution &SE, const SmallPtrSetImpl<const Value *> &EphValues,
 847     const unsigned FullUnrollTripCount, const UnrollCostEstimator UCE,
 848     const TargetTransformInfo::UnrollingPreferences &UP) {
 849   assert(FullUnrollTripCount && "should be non-zero!");
 850 
 851   if (FullUnrollTripCount > UP.FullUnrollMaxCount)
 852     return std::nullopt;
 853 
 854   // When computing the unrolled size, note that BEInsns are not replicated
 855   // like the rest of the loop body.
 856   if (UCE.getUnrolledLoopSize(UP) < UP.Threshold)
 857     return FullUnrollTripCount;
 858 
 859   // The loop isn't that small, but we still can fully unroll it if that
 860   // helps to remove a significant number of instructions.
 861   // To check that, run additional analysis on the loop.
 862   if (std::optional<EstimatedUnrollCost> Cost = analyzeLoopUnrollCost(
 863           L, FullUnrollTripCount, DT, SE, EphValues, TTI,
 864           UP.Threshold * UP.MaxPercentThresholdBoost / 100,
 865           UP.MaxIterationsCountToAnalyze)) {
 866     unsigned Boost =
 867       getFullUnrollBoostingFactor(*Cost, UP.MaxPercentThresholdBoost);
 868     if (Cost->UnrolledCost < UP.Threshold * Boost / 100)
 869       return FullUnrollTripCount;
 870   }
 871   return std::nullopt;
 872 }
