 874 static std::optional<unsigned>
 875 shouldPartialUnroll(const unsigned LoopSize, const unsigned TripCount,
 876                     const UnrollCostEstimator UCE,
 877                     const TargetTransformInfo::UnrollingPreferences &UP) {
