 889     count = TripCount;
 890   if (UP.PartialThreshold != NoThreshold) {
 891     // Reduce unroll count to be modulo of TripCount for partial unrolling.
 892     if (UCE.getUnrolledLoopSize(UP, count) > UP.PartialThreshold)
 893       count = (std::max(UP.PartialThreshold, UP.BEInsns + 1) - UP.BEInsns) /
 894         (LoopSize - UP.BEInsns);
