 913     }
 914   } else {
 915     count = TripCount;
 916   }
 917   if (count > UP.MaxCount)
 918     count = UP.MaxCount;
 919 
 920   LLVM_DEBUG(dbgs() << "  partially unrolling with count: " << count << "\n");
 921 
 922   return count;
